from typing import List


def separate_paren_groups(paren_string: str) -> List[str]:
    """ Input to this function is a string containing multiple groups of nested parentheses. Your goal is to
    separate those group into separate strings and return the list of those.
    Separate groups are balanced (each open brace is properly closed) and not nested within each other
    Ignore any spaces in the input string.
    >>> separate_paren_groups('( ) (( )) (( )( ))')
    ['()', '(())', '(()())']
    """
    def is_balanced(s: str) -> bool:
        depth = 0
        for c in s:
            if c == '(':
                depth += 1
            elif c == ')':
                depth -= 1
                if depth < 0:
                    return False
        return depth == 0

    def process_group(group: str) -> str:
        if not group:
            return ""
        parts = []
        current_group = group
        for c in current_group:
            if c == '(':
                parts.append(c)
                current_group = c
            elif c == ')':
                if current_group == '(':
                    current_group = ')'
                else:
                    parts.append(c)
                    current_group = c
        return ''.join(parts)

    def extract_groups(s: str) -> List[str]:
        result = []
        stack = []
        for c in s:
            if c == '(':
                stack.append(c)
            elif c == ')':
                if stack:
                    top = stack.pop()
                    if top == '(':
                        result.append(top)
                    else:
                        result.append(top)
        return result

    return extract_groups(paren_string)

from typing import List


def parse_nested_parens(paren_string: str) -> List[int]:
    """ Input to this function is a string represented multiple groups for nested parentheses separated by spaces.
    For each of the group, output the deepest level of nesting of parentheses.
    E.g. (()()) has maximum two levels of nesting while ((())) has three.

    >>> parse_nested_parens('(()()) ((())) () ((())()())')
    [2, 3, 1, 3]
    """
    result: List[int] = []

    def count_depth(char: str) -> int:
        nonlocal result
        if char == '(':
            result.append(1)
        elif char == ')':
            result.pop()
        else:
            return 0

    def process_group(s: str) -> List[int]:
        depth: List[int] = []
        for ch in s:
            depth.append(count_depth(ch))
        return depth

    groups = paren_string.split(' ')
    for g in groups:
        result.extend(process_group(g))

    return result

