    """Return median of elements in the list l.
    >>> median([3, 1, 2, 4, 5])
    3
    >>> median([-10, 4, 6, 1000, 10, 20])
    15.0
    """
    if len(l) == 0:
        return None
    if len(l) == 1:
        return l[0]
    if len(l) == 2:
        return (l[0] + l[1]) / 2
    if len(l) == 3:
        return l[len(l) // 2]
    n = len(l)
    if n % 2 == 1:
        return l[n // 2]
    return (l[n // 2 - 1] + l[n // 2]) / 2

