def largest_prime_factor(n: int):
    """Return the largest prime factor of n. Assume n > 1 and is not a prime.
    >>> largest_prime_factor(13195)
    29
    >>> largest_prime_factor(2048)
    2
    """
    if n <= 1:
        raise ValueError("n must be greater than 1")

    if n == 2:
        return 2

    if n % 2 == 0:
        return 2

    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return i

    return n

def largest_prime_factor(n: int):
    """Return the largest prime factor of n. Assume n > 1 and is not a prime.
    >>> largest_prime_factor(13195)
    29
    >>> largest_prime_factor(2048)
    2
    """
    if n <= 1:
        return None
    if n == 2:
        return 2

    # Factor out 2
    while n % 2 == 0:
        n //= 2

    # Check odd factors from 3 up
    i = 3
    while i * i <= n:
        while n % i == 0:
            n //= i
            i += 2
        if i * i > n:
            break

    # n is now prime
    if n == 2:
        return 2
    if n == 3:
        return 3

    return n

