    Examples
    solution([5, 8, 7, 1]) ==> 12
    solution([3, 3, 3, 3, 3]) ==> 9
    solution([30, 13, 24, 321]) ==>0
    """
    positions = [0] * len(lst)
    for i in range(len(lst)):
        positions[i] = i

    result = 0
    for i in range(len(lst) - 1):
        if positions[i] % 2 == 0:
            if lst[positions[i]] % 2 != 0:
                result += lst[positions[i]]
    return result

